css:
.ce-topbar{display:flex;align-items:center;gap:12px;margin-bottom:6px;}
  .ce-kicker{font-family:var(--mono);font-size:11px;letter-spacing:2px;text-transform:uppercase;color:var(--warn);}
  .ce-h1{font-family:var(--serif);font-weight:600;font-size:34px;line-height:1.1;margin:6px 0 8px;letter-spacing:-.01em;}
  .ce-lead{color:var(--text2);font-size:15.5px;margin:0 0 4px;max-width:60ch;}
  .ce-review-note{margin:18px 0 26px;padding:12px 15px;border:1px solid var(--warn);background:var(--warn-dim);border-radius:12px;font-size:13.5px;color:var(--text);display:flex;gap:10px;align-items:flex-start;}
  .ce-review-note b{color:var(--warn);}
  .ce-controls{position:sticky;top:0;z-index:5;background:linear-gradient(var(--bg) 72%,transparent);padding:14px 0 16px;display:flex;gap:12px;flex-wrap:wrap;align-items:center;}
  .ce-search{flex:1;min-width:200px;display:flex;align-items:center;gap:9px;background:var(--panel);border:1px solid var(--line);border-radius:11px;padding:11px 14px;}
  .ce-search svg{width:17px;height:17px;color:var(--muted);flex:none;}
  .ce-search input{flex:1;background:none;border:none;outline:none;color:var(--text);font-size:14.5px;font-family:var(--sans);}
  .ce-jump{background:var(--panel);border:1px solid var(--line);border-radius:11px;padding:11px 14px;color:var(--text);font-size:14px;font-family:var(--sans);cursor:pointer;min-width:190px;}
  .ce-count{font-family:var(--mono);font-size:11.5px;color:var(--muted);}
  .ce-card{background:var(--panel);border:1px solid var(--line);border-radius:18px;padding:26px 28px;margin:0 0 26px;scroll-margin-top:84px;overflow:hidden;}
  .ce-head{display:flex;align-items:flex-start;gap:16px;padding-bottom:18px;margin-bottom:20px;border-bottom:1px solid var(--line);}
  .ce-emblem{flex:none;width:54px;height:54px;border-radius:14px;background:var(--accent-dim);color:var(--accent-2);display:flex;align-items:center;justify-content:center;}
  .ce-emblem svg{width:30px;height:30px;}
  .ce-title{font-family:var(--serif);font-weight:600;font-size:23px;margin:2px 0 3px;line-height:1.15;}
  .ce-def{margin:0;color:var(--text2);font-size:13.5px;}
  .ce-pill{margin-left:auto;flex:none;font-family:var(--mono);font-size:10px;font-weight:600;letter-spacing:.5px;text-transform:uppercase;padding:4px 9px;border-radius:6px;background:var(--warn-dim);color:var(--warn);}
  .ce-sec{margin:0 0 20px;}
  .ce-sec:last-child{margin-bottom:0;}
  .ce-label{font-family:var(--mono);font-size:11px;letter-spacing:1.2px;text-transform:uppercase;color:var(--accent-2);margin:0 0 10px;font-weight:600;}
  .ce-suspect,.ce-pitfalls{list-style:none;margin:0;padding:0;}
  .ce-suspect li,.ce-pitfalls li{position:relative;padding:3px 0 3px 22px;font-size:14.5px;color:var(--text);}
  .ce-suspect li::before{content:"";position:absolute;left:2px;top:11px;width:7px;height:7px;border-radius:50%;background:var(--accent);}
  .ce-pitfalls li::before{content:"!";position:absolute;left:0;top:2px;width:15px;height:15px;font-family:var(--mono);font-size:11px;font-weight:700;color:var(--danger);background:var(--danger-dim);border-radius:50%;display:flex;align-items:center;justify-content:center;}
  .ce-late{font-family:var(--mono);font-size:10.5px;color:var(--warn);background:var(--warn-dim);padding:1px 6px;border-radius:4px;margin-left:4px;}
  ol.ce-actions{list-style:none;counter-reset:a;margin:0;padding:0;}
  ol.ce-actions li{counter-increment:a;position:relative;padding:5px 0 5px 38px;font-size:14.5px;min-height:26px;}
  ol.ce-actions li::before{content:counter(a);position:absolute;left:0;top:4px;width:24px;height:24px;border-radius:50%;background:var(--accent-dim);color:var(--accent-2);font-family:var(--mono);font-size:12px;font-weight:700;display:flex;align-items:center;justify-content:center;}
  table.ce-drugs{width:100%;border-collapse:collapse;font-size:13.5px;table-layout:fixed;}
  table.ce-drugs th{text-align:left;font-family:var(--mono);font-size:10.5px;letter-spacing:.5px;text-transform:uppercase;color:var(--muted);font-weight:600;padding:0 12px 8px 0;border-bottom:1px solid var(--line);}
  table.ce-drugs td{padding:9px 12px 9px 0;border-bottom:1px solid color-mix(in srgb,var(--line) 55%,transparent);vertical-align:top;word-break:break-word;}
  table.ce-drugs th:first-child,table.ce-drugs td:first-child{width:23%;font-weight:600;}
  table.ce-drugs th:nth-child(2),table.ce-drugs td:nth-child(2){width:37%;font-family:var(--mono);font-size:12px;color:var(--accent-2);}
  @media (max-width:560px){table.ce-drugs th:first-child,table.ce-drugs td:first-child{width:30%;}table.ce-drugs th:nth-child(2),table.ce-drugs td:nth-child(2){width:32%;}}
  table.ce-drugs td:last-child{color:var(--text2);}
  .ce-flow{display:flex;flex-direction:column;gap:0;}
  .ce-node{position:relative;background:var(--panel2);border:1px solid var(--line2);border-radius:10px;padding:11px 15px;font-size:13.5px;max-width:440px;}
  .ce-node:not(:last-child){margin-bottom:26px;}
  .ce-node:not(:last-child)::after{content:"";position:absolute;left:24px;bottom:-22px;width:2px;height:18px;background:var(--line2);}
  .ce-node:not(:last-child)::before{content:"";position:absolute;left:20px;bottom:-24px;border-left:5px solid transparent;border-right:5px solid transparent;border-top:6px solid var(--line2);}
  .ce-node.accent{border-color:var(--accent);background:var(--accent-dim);color:var(--text);font-weight:600;}
  ul.ce-sources{list-style:none;margin:0;padding:0;display:flex;flex-direction:column;gap:5px;}
  ul.ce-sources li{font-size:12.5px;color:var(--text2);padding-left:16px;position:relative;}
  ul.ce-sources li::before{content:"→";position:absolute;left:0;color:var(--muted);}
  .ce-after{font-size:14px;color:var(--text2);margin:0;}
  .ce-foot{margin-top:40px;text-align:center;color:var(--muted);font-size:12.5px;font-family:var(--mono);}
  .no-match{display:none;}
  @media print{
    .ce-controls,.ce-review-note,.ce-kicker{display:none;}
    .ce-card{border:1px solid #ccc;background:#fff;color:#111;page-break-inside:avoid;box-shadow:none;}
    .ce-title,.ce-h1{color:#111;} .ce-def,.ce-after,table.ce-drugs td:last-child{color:#333;}
    .ce-emblem{background:#eef7f1;color:#146A4A;} .ce-label{color:#146A4A;} table.ce-drugs td:nth-child(2){color:#146A4A;}
    .ce-node{background:#f6f8fa;border-color:#ccc;} .ce-node.accent{background:#eef7f1;border-color:#146A4A;}
  }
  @media (max-width:560px){  .ce-card{padding:20px 18px;} .ce-h1{font-size:27px;} }
  @media (hover:none){ a:hover{text-decoration:none;} }
  .ce-monitor .ce-label{margin-bottom:12px;}
  .ce-strip{margin:0 0 12px;border:1px solid var(--line);border-radius:10px;overflow:hidden;background:#0a0e13;}
  .ce-strip:last-child{margin-bottom:0;}
  .ce-strip svg{display:block;width:100%;height:78px;}
  .ce-strip figcaption{font-family:var(--mono);font-size:11.5px;color:var(--text2);padding:7px 12px;border-top:1px solid var(--line);background:var(--panel2);}
  @media print{.ce-strip{-webkit-print-color-adjust:exact;print-color-adjust:exact;}}
  .ce-strip.tall svg{height:auto;display:block;width:100%;}
  .ce-photo{margin:0;border:1px solid var(--line);border-radius:12px;overflow:hidden;background:#05070a;}
  .ce-photo img{display:block;width:100%;height:auto;max-height:360px;object-fit:contain;}
  .ce-photo figcaption{font-family:var(--mono);font-size:11px;color:var(--muted);padding:7px 12px;border-top:1px solid var(--line);line-height:1.45;}
  .ce-photo figcaption a{color:var(--text2);}
.ce-print{margin-left:auto;flex:none;display:inline-flex;align-items:center;gap:6px;background:var(--panel2);border:1px solid var(--line);color:var(--text2);border-radius:8px;padding:6px 11px;font-family:var(--mono);font-size:11px;font-weight:600;letter-spacing:.5px;cursor:pointer;transition:border-color .15s,color .15s;}
.ce-print:hover{border-color:var(--accent);color:var(--text);}
.ce-print svg{width:15px;height:15px;}
@media print{.ce-print{display:none;}}
